function minCostToEqualBaskets(basket1, basket2) {
    const diffCount = new Map();
    for (let i = 0; i < basket1.length; i++) {
        const diff = basket1[i] - basket2[i];
        diffCount.set(diff, (diffCount.get(diff) || 0) + 1);
    }

    let minCost = Infinity, cost = 0;
    for (const [diff, count] of diffCount.entries()) {
        if (count === diffCount.get(-diff)) {
            cost = 0;
            for (let i = 0; i < basket1.length; i++) {
                if (basket1[i] - basket2[i] === diff) {
                    cost += Math.min(basket1[i], basket2[i]);
                }
            }
            minCost = Math.min(minCost, cost);
        }
    }

    return minCost === Infinity ? -1 : minCost / 2;
}
```

    1. Calculate the differences between the elements of basket1 and basket2, and store the counts in a hash map (diff_count).
2. Iterate through the diff_count hash map, checking if there is an equal count for the negative difference value.
3. If there is an equal count, calculate the total cost for swaps of the current difference.
4. Keep track of the minimum total cost found.
5. Return the minimum total cost divided by 2, or -1 if no valid swaps were found.

